#!/usr/bin/env python3
"""
CI/CD pip install script for automated deployment pipeline.
Installs all requirements from requirements.txt with upgrade flag for latest versions.
"""

import subprocess
import sys
import os
import time
import logging

# Configure logging
logging.basicConfig(
    level=logging.INFO,
    format="%(asctime)s [%(levelname)s] %(message)s",
    handlers=[
        logging.StreamHandler(sys.stdout),
    ],
)
logger = logging.getLogger(__name__)


def check_pip_available():
    """Verify that pip is available in the current environment."""
    try:
        result = subprocess.run(
            [sys.executable, "-m", "pip", "--version"],
            capture_output=True,
            text=True,
            check=True,
        )
        logger.info(f"pip found: {result.stdout.strip()}")
        return True
    except (subprocess.CalledProcessError, FileNotFoundError):
        logger.error("pip is not available in the current Python environment.")
        return False


def upgrade_pip():
    """Upgrade pip itself to the latest version."""
    logger.info("Upgrading pip to latest version...")
    try:
        result = subprocess.run(
            [sys.executable, "-m", "pip", "install", "--upgrade", "pip"],
            capture_output=True,
            text=True,
            check=True,
        )
        logger.info("pip upgraded successfully.")
        logger.debug(result.stdout)
    except subprocess.CalledProcessError as e:
        logger.warning(f"Failed to upgrade pip: {e.stderr}")
        logger.warning("Continuing with existing pip version...")


def find_requirements_file(filename="requirements.txt"):
    """Locate the requirements file, checking common paths."""
    search_paths = [
        filename,
        os.path.join(os.getcwd(), filename),
        os.path.join(os.path.dirname(os.path.abspath(__file__)), filename),
    ]

    # Also check for WORKSPACE_DIR environment variable (common in CI/CD)
    workspace_dir = os.environ.get("WORKSPACE_DIR") or os.environ.get("WORKSPACE")
    if workspace_dir:
        search_paths.append(os.path.join(workspace_dir, filename))

    for path in search_paths:
        if os.path.isfile(path):
            logger.info(f"Found requirements file: {os.path.abspath(path)}")
            return path

    return None


def install_requirements(requirements_file="requirements.txt"):
    """
    Install all packages from requirements.txt with --upgrade flag.
    Uses no hash verification for speed in CI/CD pipeline.
    """
    req_path = find_requirements_file(requirements_file)

    if req_path is None:
        logger.error(
            f"Requirements file '{requirements_file}' not found. "
            "Please ensure the file exists in the project directory."
        )
        return False

    # Log the contents of requirements file for traceability
    logger.info(f"Installing dependencies from: {os.path.abspath(req_path)}")
    try:
        with open(req_path, "r") as f:
            contents = f.read().strip()
            if not contents:
                logger.warning("Requirements file is empty. Nothing to install.")
                return True
            logger.info("Requirements to install:")
            for line in contents.splitlines():
                line = line.strip()
                if line and not line.startswith("#"):
                    logger.info(f"  - {line}")
    except IOError as e:
        logger.error(f"Error reading requirements file: {e}")
        return False

    # Build the pip install command
    cmd = [
        sys.executable,
        "-m",
        "pip",
        "install",
        "-r",
        req_path,
        "--upgrade",
        "--no-cache-dir",  # Don't use cache for clean CI/CD builds
        "--disable-pip-version-check",  # Skip pip version check for speed
    ]

    # Add trusted hosts if configured via environment
    trusted_host = os.environ.get("PIP_TRUSTED_HOST")
    if trusted_host:
        cmd.extend(["--trusted-host", trusted_host])

    # Add custom index URL if configured
    index_url = os.environ.get("PIP_INDEX_URL")
    if index_url:
        cmd.extend(["--index-url", index_url])

    extra_index_url = os.environ.get("PIP_EXTRA_INDEX_URL")
    if extra_index_url:
        cmd.extend(["--extra-index-url", extra_index_url])

    logger.info(f"Running command: {' '.join(cmd)}")

    start_time = time.time()

    try:
        result = subprocess.run(
            cmd,
            text=True,
            check=True,
            stdout=subprocess.PIPE,
            stderr=subprocess.STDOUT,
        )
        elapsed = time.time() - start_time
        logger.info(result.stdout)
        logger.info(
            f"All dependencies installed successfully in {elapsed:.2f} seconds."
        )
        return True

    except subprocess.CalledProcessError as e:
        elapsed = time.time() - start_time
        logger.error(f"Dependency installation failed after {elapsed:.2f} seconds.")
        logger.error(f"Exit code: {e.returncode}")
        if e.stdout:
            logger.error(f"Output:\n{e.stdout}")
        return False


def verify_installation(requirements_file="requirements.txt"):
    """Verify that all required packages are installed."""
    req_path = find_requirements_file(requirements_file)
    if req_path is None:
        return False

    logger.info("Verifying installed packages...")

    try:
        result = subprocess.run(
            [sys.executable, "-m", "pip", "check"],
            capture_output=True,
            text=True,
        )
        if result.returncode == 0:
            logger.info("All package dependencies are satisfied.")
        else:
            logger.warning(f"Dependency check warnings:\n{result.stdout}")

        # List installed packages for CI/CD audit trail
        list_result = subprocess.run(
            [sys.executable, "-m", "pip", "list", "--format=columns"],
            capture_output=True,
            text=True,
        )
        logger.info(f"Installed packages:\n{list_result.stdout}")
        return True

    except subprocess.CalledProcessError as e:
        logger.error(f"Verification failed: {e}")
        return False


def main():
    """Main entry point for CI/CD dependency installation."""
    logger.info("=" * 60)
    logger.info("CI/CD Dependency Installation Script")
    logger.info("=" * 60)
    logger.info(f"Python executable: {sys.executable}")
    logger.info(f"Python version: {sys.version}")
    logger.info(f"Working directory: {os.getcwd()}")
    logger.info("=" * 60)

    # Determine which requirements file to use
    requirements_file = os.environ.get("REQUIREMENTS_FILE", "requirements.txt")

    # Step 1: Check pip is available
    if not check_pip_available():
        logger.error("Cannot proceed without pip. Exiting.")
        sys.exit(1)

    # Step 2: Upgrade pip
    upgrade_pip()

    # Step 3: Install requirements
    if not install_requirements(requirements_file):
        logger.error("Dependency installation failed. Exiting with error.")
        sys.exit(1)

    # Step 4: Verify installation
    verify_installation(requirements_file)

    logger.info("=" * 60)
    logger.info("Dependency installation completed successfully!")
    logger.info("=" * 60)
    sys.exit(0)


if __name__ == "__main__":
    main()